@Component
public class ArchiveInvoiceWorker {

    @JobWorker(type = "archive-invoice")
    public void handleJob(
        @Variable("invoiceId") String invoiceId,
        @Variable("invoice") JsonNode invoiceJson) {

        try {
            service.archiveInvoice(invoiceId, invoiceJson);
        } catch (WiredLegacyException e) {
            // Trigger BPMN error → activates error boundary event
            throw new BpmnError("LEGACY_ERROR_ARCHIVE", e.getMessage());
        }
    }
}
